    pdf.section_heading("2", "GRANT OF LICENSE AND ACCESS")
    pdf.subsection_heading("2.1", "License Grant.")
    pdf.body_text("Subject to the terms and conditions of this Agreement, Provider hereby grants to Customer a non-exclusive, non-transferable, non-sublicensable right to access and use the Service during the Term solely for Customer's internal business operations.")
    pdf.subsection_heading("2.2", "Restrictions.")
    pdf.body_text("Customer shall not: (a) sublicense, sell, resell, transfer, assign, or distribute the Service; (b) modify or make derivative works based upon the Service; (c) reverse engineer, disassemble, or decompile the Service; (d) access the Service to build a competitive product or service; or (e) use the Service in violation of applicable laws or regulations.")
    pdf.section_heading("3", "FEES AND PAYMENT")
    pdf.subsection_heading("3.1", "Subscription Fees.")
